  "inlineSchema": "// ============================================\n// Schema Prisma — ERP Juds\n// ============================================\n// Modelos: Insumo, Produto, Receita, Producao, Movimentacao\n// Provider: PostgreSQL\n// ============================================\n\ngenerator client {\n  provider = \"prisma-client\"\n  output   = \"../generated/prisma\"\n}\n\ndatasource db {\n  provider = \"postgresql\"\n}\n\n// ============================================\n// ENUMS\n// ============================================\n\n/// Unidade de medida padrão para insumos e receitas\nenum UnidadeMedida {\n  KG // Quilograma\n  G // Grama\n  L // Litro\n  ML // Mililitro\n  UN // Unidade\n}\n\n/// Tipo de movimentação de estoque\nenum TipoMovimentacao {\n  ENTRADA // Compra / reposição de estoque\n  SAIDA // Venda ou consumo em produção\n  AJUSTE // Ajuste manual de inventário\n  PRODUCAO // Saída automática por produção\n}\n\n/// Papel do usuário no sistema\nenum UserRole {\n  ADMIN // Acesso total ao sistema\n  OPERADOR // Acesso restrito (produção/estoque)\n}\n\n// ============================================\n// MODEL: User (Usuário do Sistema)\n// ============================================\n\n/// Usuário autenticado do sistema ERP.\nmodel User {\n  id           Int      @id @default(autoincrement())\n  email        String   @unique @db.VarChar(255)\n  nome         String   @db.VarChar(150)\n  senha        String   @db.VarChar(255) // Hash bcrypt\n  role         UserRole @default(OPERADOR)\n  ativo        Boolean  @default(true)\n  criadoEm     DateTime @default(now()) @map(\"criado_em\")\n  atualizadoEm DateTime @updatedAt @map(\"atualizado_em\")\n\n  @@map(\"users\")\n}\n\n// ============================================\n// MODEL: Insumo (Matéria-prima)\n// ============================================\n\n/// Matéria-prima usada na produção dos produtos.\n/// Ex: Farinha de Trigo, Açúcar, Manteiga, Fermento.\nmodel Insumo {\n  id            Int           @id @default(autoincrement())\n  nome          String        @db.VarChar(150)\n  descricao     String?       @db.Text\n  unidade       UnidadeMedida\n  estoqueAtual  Float         @default(0) @map(\"estoque_atual\")\n  estoqueMin    Float         @default(0) @map(\"estoque_min\")\n  custoUnitario Float         @default(0) @map(\"custo_unitario\")\n  ativo         Boolean       @default(true)\n  criadoEm      DateTime      @default(now()) @map(\"criado_em\")\n  atualizadoEm  DateTime      @updatedAt @map(\"atualizado_em\")\n\n  // Relacionamentos\n  receitaItens  ReceitaItem[]\n  movimentacoes Movimentacao[]\n\n  @@map(\"insumos\")\n}\n\n// ============================================\n// MODEL: Produto (Produto Final)\n// ============================================\n\n/// Produto final vendido ao cliente.\n/// Ex: Pão Francês, Bolo de Chocolate, Rosca.\nmodel Produto {\n  id           Int           @id @default(autoincrement())\n  nome         String        @db.VarChar(150)\n  descricao    String?       @db.Text\n  precoVenda   Float         @default(0) @map(\"preco_venda\")\n  estoqueAtual Float         @default(0) @map(\"estoque_atual\")\n  estoqueMin   Float         @default(0) @map(\"estoque_min\")\n  unidade      UnidadeMedida @default(UN)\n  ativo        Boolean       @default(true)\n  criadoEm     DateTime      @default(now()) @map(\"criado_em\")\n  atualizadoEm DateTime      @updatedAt @map(\"atualizado_em\")\n\n  // Relacionamentos\n  receitas  Receita[]\n  producoes Producao[]\n\n  @@map(\"produtos\")\n}\n\n// ============================================\n// MODEL: Receita (Ficha Técnica do Produto)\n// ============================================\n\n/// Ficha técnica: define quais insumos e quantidades\n/// são necessários para produzir um determinado produto.\n/// Um produto pode ter várias receitas (ex: versões diferentes).\nmodel Receita {\n  id           Int      @id @default(autoincrement())\n  nome         String   @db.VarChar(200)\n  descricao    String?  @db.Text\n  rendimento   Float    @default(1) // Quantas unidades do produto a receita rende\n  ativo        Boolean  @default(true)\n  criadoEm     DateTime @default(now()) @map(\"criado_em\")\n  atualizadoEm DateTime @updatedAt @map(\"atualizado_em\")\n\n  // FK → Produto\n  produtoId Int     @map(\"produto_id\")\n  produto   Produto @relation(fields: [produtoId], references: [id], onDelete: Cascade)\n\n  // Relacionamentos\n  itens     ReceitaItem[]\n  producoes Producao[]\n\n  @@map(\"receitas\")\n}\n\n// ============================================\n// MODEL: ReceitaItem (Ingrediente da Receita)\n// ============================================\n\n/// Tabela associativa: define cada ingrediente (insumo)\n/// e sua quantidade dentro de uma receita.\nmodel ReceitaItem {\n  id         Int   @id @default(autoincrement())\n  quantidade Float // Quantidade do insumo necessária\n\n  // FK → Receita\n  receitaId Int     @map(\"receita_id\")\n  receita   Receita @relation(fields: [receitaId], references: [id], onDelete: Cascade)\n\n  // FK → Insumo\n  insumoId Int    @map(\"insumo_id\")\n  insumo   Insumo @relation(fields: [insumoId], references: [id], onDelete: Restrict)\n\n  @@unique([receitaId, insumoId]) // Um insumo aparece só uma vez por receita\n  @@map(\"receita_itens\")\n}\n\n// ============================================\n// MODEL: Producao (Registro de Produção)\n// ============================================\n\n/// Registra cada execução de uma receita.\n/// Ao criar uma produção, o sistema automaticamente:\n///   1. Debita os insumos do estoque (via Movimentacao PRODUCAO)\n///   2. Credita o produto final no estoque\nmodel Producao {\n  id                  Int      @id @default(autoincrement())\n  quantidadeProduzida Float    @map(\"quantidade_produzida\")\n  custoTotal          Float    @default(0) @map(\"custo_total\")\n  observacao          String?  @db.Text\n  produzidoEm         DateTime @default(now()) @map(\"produzido_em\")\n  criadoEm            DateTime @default(now()) @map(\"criado_em\")\n\n  // FK → Receita (qual receita foi executada)\n  receitaId Int     @map(\"receita_id\")\n  receita   Receita @relation(fields: [receitaId], references: [id], onDelete: Restrict)\n\n  // FK → Produto (qual produto foi gerado)\n  produtoId Int     @map(\"produto_id\")\n  produto   Produto @relation(fields: [produtoId], references: [id], onDelete: Restrict)\n\n  // Relacionamentos\n  movimentacoes Movimentacao[]\n\n  @@map(\"producoes\")\n}\n\n// ============================================\n// MODEL: Movimentacao (Movimentação de Estoque)\n// ============================================\n\n/// Registra toda e qualquer movimentação de estoque de insumos.\n/// Tipos: ENTRADA (compra), SAIDA (venda/consumo), AJUSTE, PRODUCAO.\nmodel Movimentacao {\n  id            Int              @id @default(autoincrement())\n  tipo          TipoMovimentacao\n  quantidade    Float\n  custoUnitario Float?           @map(\"custo_unitario\")\n  observacao    String?          @db.Text\n  criadoEm      DateTime         @default(now()) @map(\"criado_em\")\n\n  // FK → Insumo (qual insumo foi movimentado)\n  insumoId Int    @map(\"insumo_id\")\n  insumo   Insumo @relation(fields: [insumoId], references: [id], onDelete: Restrict)\n\n  // FK → Producao (opcional: se a movimentação foi gerada por uma produção)\n  producaoId Int?      @map(\"producao_id\")\n  producao   Producao? @relation(fields: [producaoId], references: [id], onDelete: SetNull)\n\n  @@index([insumoId, criadoEm])\n  @@index([tipo])\n  @@map(\"movimentacoes\")\n}\n",
